external_knowledge:
- 'brightest stars' refers to the products with the highest average ratings;
- 'electronics universe' refers to the 'Electronics' product category;
- 'average sparkle' refers to the average rating of a product;
- 'total twinkles' refers to the total number of reviews for a product;
- 'most dazzling review' refers to the review with the highest 'helpful_votes';
- 'sparkle that outshines others' refers to the average rating used for ranking products.

sql:
SELECT asin, average_rating, total_reviews, most_helpful_review_id 
FROM review_insights 
WHERE total_reviews < 100;
